CREATE TABLE tbl_fish_render_states (
    id                SERIAL PRIMARY KEY,
    render_family_id  INTEGER      NOT NULL REFERENCES tbl_fish_render_families(id),
    state_code        VARCHAR(100) NOT NULL,
    prefix            TEXT,
    frame_array       TEXT[]       NOT NULL DEFAULT '{}',
    is_default        BOOLEAN      NOT NULL DEFAULT FALSE,

    -- audit columns
    status_id   SMALLINT    NOT NULL DEFAULT 1,
    "order"     INTEGER,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by  INTEGER,
    updated_at  TIMESTAMPTZ,
    updated_by  INTEGER,
    deleted_at  TIMESTAMPTZ,
    deleted_by  INTEGER,

    UNIQUE (render_family_id, state_code)
);

